(function($) {

$.fn.responsiveMenu = function(options) {
    if (options === undefined) options = {};
    var defaults = {
        menuID: "menu",
        toggleClass: "menu-toggle",
        toggleText: "",
        maxWidth: "60em"
    };
    var vars = $.extend({}, defaults, options);
    var menuID = vars.menuID;
    var toggleID = vars.toggleID || vars.toggleClass;
    var toggleClass = vars.toggleClass;
    var toggleText = vars.toggleText;
    var maxWidth = vars.maxWidth;
    var $this = $(this);
    var $menu = $("#" + menuID);

    if (typeof matchMedia == "function") {
        var mq = window.matchMedia("(max-width: " + maxWidth + ")");
        mq.addListener(widthChange);
        widthChange(mq);
    }

    function widthChange(mq) {
        if (mq.matches) {
            $menu.find("ul.sub-menu").css({ display: "block" });
            $menu.find("li ul.sub-menu").css({ visibility: "visible", display: "block" });
            $menu.find("li.menu-item-has-children").unbind("mouseenter mouseleave");
            $menu.find("li.menu-item-has-children ul.sub-menu").each(function() {
                $(this).hide();
                $(this).parent().find(".submenu-dropdown-toggle").removeClass("active");
            });
        } else {
            $menu.find("ul.sub-menu").css({ display: "none" });
            $menu.find("li.menu-item-has-children").hover(function() {
                $(this).find("ul:first").css({ visibility: "visible", display: "none" }).slideDown(300);
            }, function() {
                $(this).find("ul:first").css({ visibility: "hidden" });
            });
        }
    }

    $this.before('<button id="' + toggleID + '" class="' + toggleClass + '">' + toggleText + '</button>');
    $menu.find("li.menu-item-has-children").prepend('<span class="submenu-dropdown-toggle"></span>');

    $("#" + toggleID).on("click", function() {
        $menu.slideToggle();
        $(this).toggleClass("active");
    });

    $menu.find("li.menu-item-has-children .sub-menu").each(function() {
        $(this).hide();
    });

    $menu.find(".submenu-dropdown-toggle").on("click", function() {
        $(this).parent().find("ul:first").slideToggle();
        $(this).toggleClass("active");
    });
};

$.fn.flipMenu = function(options) {
    if (options === undefined) options = {};
    var defaults = {
        menuID: "menu",
        flipMenuID: "menu",
        toggleClass: "menu-toggle",
        toggleText: ""
    };
    var vars = $.extend({}, defaults, options);
    var menuID = vars.menuID;
    var flipMenuID = vars.flipMenuID;
    var toggleID = vars.toggleID || vars.toggleClass;
    var toggleClass = vars.toggleClass;
    var toggleText = vars.toggleText;
    var $this = $(this);
    var $menu = $("#" + menuID);
    var $flipMenu = $("#" + flipMenuID);

    $this.before('<button id="' + toggleID + '" class="' + toggleClass + '">' + toggleText + '</button>');

    $("#" + toggleID).on("click", function() {
        if ($flipMenu.is(":visible")) {
            $flipMenu.slideToggle();
            $menu.delay(400).slideToggle();
        } else {
            $menu.slideToggle();
        }
        $(this).toggleClass("active");
    });
};

$(document).ready(function() {
    $("#mainnav").responsiveMenu({
        menuID: "mainnav-menu",
        toggleID: "mainnav-toggle",
        toggleClass: "mainnav-toggle",
        maxWidth: "60em"
    });

    $("#topnav").responsiveMenu({
        menuID: "topnav-menu",
        toggleID: "topnav-toggle-tablet",
        toggleClass: "topnav-toggle",
        maxWidth: "60em"
    });

    $("#navi-social-icons").flipMenu({
        menuID: "social-icons-menu",
        flipMenuID: "topnav-menu",
        toggleID: "social-menu-toggle",
        toggleClass: "social-menu-toggle"
    });

    $("#topnav").flipMenu({
        menuID: "topnav-menu",
        flipMenuID: "social-icons-menu",
        toggleID: "topnav-toggle-phone",
        toggleClass: "topnav-toggle"
    });
});

})(jQuery);
